from __future__ import annotations

from pathlib import Path
import re
import shutil
import sys

ROOT = Path(__file__).resolve().parent
MAIN = ROOT / "main.py"
SOUNDS_SRC = ROOT / "sounds"
SOUNDS_DST = ROOT / "sounds"

PATCH_CODE = '\n# === ARENA SOUND OPTIONS PATCH V4 START ===\n# Added by apply_sound_options_patch_v4.py\nimport json as _arena_json\nimport sys as _arena_sys\nfrom pathlib import Path as _ArenaPath\n\n_ARENA_AUDIO_SETTINGS_FILE = _ArenaPath(__file__).with_name("arena_sound_settings.json")\n_ARENA_AUDIO_STATE = {\n    "loaded": False,\n    "bgm_started": False,\n    "panel_open": False,\n    "bgm_volume": 0.18,\n    "sfx_volume": 0.78,\n    "bgm_enabled": True,\n    "sfx_enabled": True,\n    "sounds": {},\n    "last_list_ids": {},\n    "last_fighter_awaken": {},\n    "played_annihilation_ids": set(),\n}\n\ndef _arena_audio_resource_path(relative_path):\n    base = getattr(_arena_sys, "_MEIPASS", None)\n    if base:\n        return str(_ArenaPath(base) / relative_path)\n    return str(_ArenaPath(__file__).resolve().parent / relative_path)\n\ndef _arena_audio_load_settings():\n    try:\n        if _ARENA_AUDIO_SETTINGS_FILE.exists():\n            data = _arena_json.loads(_ARENA_AUDIO_SETTINGS_FILE.read_text(encoding="utf-8"))\n            _ARENA_AUDIO_STATE["bgm_volume"] = float(data.get("bgm_volume", _ARENA_AUDIO_STATE["bgm_volume"]))\n            _ARENA_AUDIO_STATE["sfx_volume"] = float(data.get("sfx_volume", _ARENA_AUDIO_STATE["sfx_volume"]))\n            _ARENA_AUDIO_STATE["bgm_enabled"] = bool(data.get("bgm_enabled", _ARENA_AUDIO_STATE["bgm_enabled"]))\n            _ARENA_AUDIO_STATE["sfx_enabled"] = bool(data.get("sfx_enabled", _ARENA_AUDIO_STATE["sfx_enabled"]))\n    except Exception:\n        pass\n\ndef _arena_audio_save_settings():\n    try:\n        data = {\n            "bgm_volume": _ARENA_AUDIO_STATE["bgm_volume"],\n            "sfx_volume": _ARENA_AUDIO_STATE["sfx_volume"],\n            "bgm_enabled": _ARENA_AUDIO_STATE["bgm_enabled"],\n            "sfx_enabled": _ARENA_AUDIO_STATE["sfx_enabled"],\n        }\n        _ARENA_AUDIO_SETTINGS_FILE.write_text(_arena_json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")\n    except Exception:\n        pass\n\ndef _arena_audio_init():\n    if _ARENA_AUDIO_STATE["loaded"]:\n        return\n    _ARENA_AUDIO_STATE["loaded"] = True\n    _arena_audio_load_settings()\n    try:\n        if not pygame.mixer.get_init():\n            pygame.mixer.init()\n    except Exception:\n        return\n\n    sound_files = {\n        "hit": "hit.wav",\n        "dodge": "dodge.wav",\n        "laser": "laser.wav",\n        "slash": "slash.wav",\n        "moon_slash": "moon_slash.wav",\n        "geonwoo_boom": "geonwoo_boom.wav",\n        "explosion": "explosion.wav",\n        "jaemin_awaken": "jaemin_awaken.wav",\n        "cow_moo": "cow_moo.wav",\n    }\n    for key, filename in sound_files.items():\n        try:\n            path = _arena_audio_resource_path("sounds/" + filename)\n            _ARENA_AUDIO_STATE["sounds"][key] = pygame.mixer.Sound(path)\n        except Exception:\n            pass\n\ndef arena_play_sound(sound_name, volume=1.0):\n    _arena_audio_init()\n    if not _ARENA_AUDIO_STATE["sfx_enabled"] or _ARENA_AUDIO_STATE["sfx_volume"] <= 0:\n        return\n    sound = _ARENA_AUDIO_STATE["sounds"].get(sound_name)\n    if not sound:\n        return\n    try:\n        sound.set_volume(max(0.0, min(1.0, _ARENA_AUDIO_STATE["sfx_volume"] * volume)))\n        sound.play()\n    except Exception:\n        pass\n\ndef _arena_audio_start_bgm():\n    _arena_audio_init()\n    if _ARENA_AUDIO_STATE["bgm_started"]:\n        return\n    _ARENA_AUDIO_STATE["bgm_started"] = True\n    try:\n        bgm_path = _arena_audio_resource_path("sounds/bgm.wav")\n        pygame.mixer.music.stop()\n        pygame.mixer.music.load(bgm_path)\n        pygame.mixer.music.set_volume(_ARENA_AUDIO_STATE["bgm_volume"] if _ARENA_AUDIO_STATE["bgm_enabled"] else 0)\n        pygame.mixer.music.play(-1)\n    except Exception:\n        pass\n\ndef _arena_audio_apply_bgm_volume():\n    try:\n        pygame.mixer.music.set_volume(_ARENA_AUDIO_STATE["bgm_volume"] if _ARENA_AUDIO_STATE["bgm_enabled"] else 0)\n    except Exception:\n        pass\n\ndef _arena_get_obj_value(obj, name, default=None):\n    try:\n        if isinstance(obj, dict):\n            return obj.get(name, default)\n        return getattr(obj, name, default)\n    except Exception:\n        return default\n\ndef _arena_audio_monitor_game_events():\n    # This uses the existing game_state/fighters variables without needing to rewrite the whole game loop.\n    gs = globals().get("game_state")\n    if isinstance(gs, dict):\n        list_to_sound = {\n            "moon_slashes": "moon_slash",\n            "cow_charges": "cow_moo",\n        }\n        for list_name, sound_name in list_to_sound.items():\n            value = gs.get(list_name)\n            if isinstance(value, list):\n                ids = set(id(item) for item in value)\n                old_ids = _ARENA_AUDIO_STATE["last_list_ids"].get(list_name)\n                if old_ids is not None and len(ids - old_ids) > 0:\n                    arena_play_sound(sound_name, 1.0)\n                _ARENA_AUDIO_STATE["last_list_ids"][list_name] = ids\n\n        ann = gs.get("geonwoo_annihilation")\n        if ann is not None:\n            ann_id = id(ann)\n            explode_time = _arena_get_obj_value(ann, "explode_time", None)\n            should_boom = explode_time is None\n            try:\n                should_boom = should_boom or pygame.time.get_ticks() >= int(explode_time)\n            except Exception:\n                should_boom = True\n            if should_boom and ann_id not in _ARENA_AUDIO_STATE["played_annihilation_ids"]:\n                _ARENA_AUDIO_STATE["played_annihilation_ids"].add(ann_id)\n                arena_play_sound("geonwoo_boom", 1.0)\n\n    fighters_value = globals().get("fighters")\n    if isinstance(fighters_value, list):\n        for fighter in fighters_value:\n            if _arena_get_obj_value(fighter, "character_key") != "jaemin":\n                continue\n            fid = _arena_get_obj_value(fighter, "fighter_id", id(fighter))\n            awakened = bool(_arena_get_obj_value(fighter, "is_awakened", False))\n            alive = bool(_arena_get_obj_value(fighter, "is_alive", lambda: True)() if callable(_arena_get_obj_value(fighter, "is_alive", None)) else True)\n            old = _ARENA_AUDIO_STATE["last_fighter_awaken"].get(fid, False)\n            if awakened and not old and alive:\n                arena_play_sound("jaemin_awaken", 0.95)\n            _ARENA_AUDIO_STATE["last_fighter_awaken"][fid] = awakened\n\ndef _arena_audio_ui_rects():\n    w = int(globals().get("WIDTH", 1050))\n    return {\n        "button": pygame.Rect(w - 156, 12, 140, 34),\n        "panel": pygame.Rect(w - 286, 52, 270, 158),\n        "bgm_toggle": pygame.Rect(w - 270, 96, 60, 28),\n        "bgm_minus": pygame.Rect(w - 196, 96, 34, 28),\n        "bgm_plus": pygame.Rect(w - 154, 96, 34, 28),\n        "sfx_toggle": pygame.Rect(w - 270, 144, 60, 28),\n        "sfx_minus": pygame.Rect(w - 196, 144, 34, 28),\n        "sfx_plus": pygame.Rect(w - 154, 144, 34, 28),\n    }\n\ndef _arena_audio_handle_click(pos):\n    rects = _arena_audio_ui_rects()\n    if rects["button"].collidepoint(pos):\n        _ARENA_AUDIO_STATE["panel_open"] = not _ARENA_AUDIO_STATE["panel_open"]\n        return True\n    if not _ARENA_AUDIO_STATE["panel_open"]:\n        return False\n    if not rects["panel"].collidepoint(pos):\n        return False\n\n    changed = False\n    if rects["bgm_toggle"].collidepoint(pos):\n        _ARENA_AUDIO_STATE["bgm_enabled"] = not _ARENA_AUDIO_STATE["bgm_enabled"]\n        changed = True\n    elif rects["sfx_toggle"].collidepoint(pos):\n        _ARENA_AUDIO_STATE["sfx_enabled"] = not _ARENA_AUDIO_STATE["sfx_enabled"]\n        changed = True\n    elif rects["bgm_minus"].collidepoint(pos):\n        _ARENA_AUDIO_STATE["bgm_volume"] = max(0.0, round(_ARENA_AUDIO_STATE["bgm_volume"] - 0.05, 2))\n        changed = True\n    elif rects["bgm_plus"].collidepoint(pos):\n        _ARENA_AUDIO_STATE["bgm_volume"] = min(1.0, round(_ARENA_AUDIO_STATE["bgm_volume"] + 0.05, 2))\n        _ARENA_AUDIO_STATE["bgm_enabled"] = True\n        changed = True\n    elif rects["sfx_minus"].collidepoint(pos):\n        _ARENA_AUDIO_STATE["sfx_volume"] = max(0.0, round(_ARENA_AUDIO_STATE["sfx_volume"] - 0.05, 2))\n        changed = True\n    elif rects["sfx_plus"].collidepoint(pos):\n        _ARENA_AUDIO_STATE["sfx_volume"] = min(1.0, round(_ARENA_AUDIO_STATE["sfx_volume"] + 0.05, 2))\n        _ARENA_AUDIO_STATE["sfx_enabled"] = True\n        changed = True\n\n    if changed:\n        _arena_audio_apply_bgm_volume()\n        _arena_audio_save_settings()\n        return True\n    return True\n\ndef _arena_audio_draw_button_text(surface, rect, text, font_obj, bg, fg=(245, 245, 245)):\n    try:\n        pygame.draw.rect(surface, bg, rect, border_radius=8)\n        pygame.draw.rect(surface, (230, 230, 230), rect, 1, border_radius=8)\n        label = font_obj.render(text, True, fg)\n        surface.blit(label, label.get_rect(center=rect.center))\n    except Exception:\n        pass\n\ndef _arena_audio_draw_ui():\n    try:\n        target_screen = globals().get("screen")\n        if target_screen is None:\n            return\n        rects = _arena_audio_ui_rects()\n        font_small = pygame.font.SysFont("malgungothic", 18)\n        font_tiny = pygame.font.SysFont("malgungothic", 15)\n        _arena_audio_draw_button_text(target_screen, rects["button"], "⚙ SOUND", font_small, (45, 45, 55))\n\n        if not _ARENA_AUDIO_STATE["panel_open"]:\n            return\n\n        panel = rects["panel"]\n        panel_surface = pygame.Surface((panel.width, panel.height), pygame.SRCALPHA)\n        panel_surface.fill((22, 22, 30, 230))\n        target_screen.blit(panel_surface, panel.topleft)\n        pygame.draw.rect(target_screen, (235, 235, 245), panel, 2, border_radius=10)\n\n        title = font_small.render("Sound Options", True, (255, 255, 255))\n        target_screen.blit(title, (panel.x + 14, panel.y + 12))\n\n        bgm_label = font_tiny.render(f"BGM  {int(_ARENA_AUDIO_STATE[\'bgm_volume\'] * 100)}%", True, (235, 235, 235))\n        sfx_label = font_tiny.render(f"SFX  {int(_ARENA_AUDIO_STATE[\'sfx_volume\'] * 100)}%", True, (235, 235, 235))\n        target_screen.blit(bgm_label, (panel.x + 14, panel.y + 47))\n        target_screen.blit(sfx_label, (panel.x + 14, panel.y + 95))\n\n        _arena_audio_draw_button_text(\n            target_screen, rects["bgm_toggle"],\n            "ON" if _ARENA_AUDIO_STATE["bgm_enabled"] else "OFF",\n            font_tiny,\n            (55, 120, 70) if _ARENA_AUDIO_STATE["bgm_enabled"] else (115, 55, 55),\n        )\n        _arena_audio_draw_button_text(target_screen, rects["bgm_minus"], "-", font_tiny, (60, 60, 70))\n        _arena_audio_draw_button_text(target_screen, rects["bgm_plus"], "+", font_tiny, (60, 60, 70))\n\n        _arena_audio_draw_button_text(\n            target_screen, rects["sfx_toggle"],\n            "ON" if _ARENA_AUDIO_STATE["sfx_enabled"] else "OFF",\n            font_tiny,\n            (55, 120, 70) if _ARENA_AUDIO_STATE["sfx_enabled"] else (115, 55, 55),\n        )\n        _arena_audio_draw_button_text(target_screen, rects["sfx_minus"], "-", font_tiny, (60, 60, 70))\n        _arena_audio_draw_button_text(target_screen, rects["sfx_plus"], "+", font_tiny, (60, 60, 70))\n    except Exception:\n        pass\n\n_arena_original_event_get = pygame.event.get\ndef _arena_audio_event_get(*args, **kwargs):\n    events = list(_arena_original_event_get(*args, **kwargs))\n    kept = []\n    for event in events:\n        try:\n            if event.type == pygame.MOUSEBUTTONDOWN and event.button == 1:\n                if _arena_audio_handle_click(event.pos):\n                    continue\n        except Exception:\n            pass\n        kept.append(event)\n    return kept\npygame.event.get = _arena_audio_event_get\n\n_arena_original_display_flip = pygame.display.flip\ndef _arena_audio_display_flip():\n    _arena_audio_start_bgm()\n    _arena_audio_apply_bgm_volume()\n    _arena_audio_monitor_game_events()\n    _arena_audio_draw_ui()\n    return _arena_original_display_flip()\npygame.display.flip = _arena_audio_display_flip\n\n_arena_original_display_update = pygame.display.update\ndef _arena_audio_display_update(*args, **kwargs):\n    _arena_audio_start_bgm()\n    _arena_audio_apply_bgm_volume()\n    _arena_audio_monitor_game_events()\n    _arena_audio_draw_ui()\n    return _arena_original_display_update(*args, **kwargs)\npygame.display.update = _arena_audio_display_update\n# === ARENA SOUND OPTIONS PATCH V4 END ===\n'

def fail(message: str) -> None:
    print("[ERROR]", message)
    raise SystemExit(1)

def copy_sounds() -> None:
    if not SOUNDS_SRC.exists():
        fail("sounds folder is missing next to this patch script.")
    SOUNDS_DST.mkdir(exist_ok=True)
    for src in SOUNDS_SRC.iterdir():
        if src.is_file():
            shutil.copy2(src, SOUNDS_DST / src.name)
    print("[OK] Sound files copied to sounds/")

def patch_main() -> None:
    if not MAIN.exists():
        fail("main.py was not found. Put this patch in the same folder as main.py.")

    text = MAIN.read_text(encoding="utf-8")
    backup = ROOT / "main_before_sound_options_v4.py"
    if not backup.exists():
        backup.write_text(text, encoding="utf-8")
        print("[OK] Backup created:", backup.name)

    # Remove previous V4 block if the patch was already applied.
    text = re.sub(
        r"\n?# === ARENA SOUND OPTIONS PATCH V4 START ===.*?# === ARENA SOUND OPTIONS PATCH V4 END ===\n?",
        "\n",
        text,
        flags=re.S,
    )

    if "# === ARENA SOUND OPTIONS PATCH V4 START ===" in text:
        fail("Could not remove old patch block cleanly.")

    marker = "pygame.init()"
    if marker not in text:
        fail("Could not find pygame.init() in main.py.")

    text = text.replace(marker, marker + "\n\n" + PATCH_CODE + "\n", 1)
    MAIN.write_text(text, encoding="utf-8")
    print("[OK] main.py patched with sound options UI.")

def main() -> None:
    copy_sounds()
    patch_main()
    print()
    print("[DONE] Sound Options Patch V4 applied.")
    print("Run the game with: python main.py")
    print("In the game, click the top-right SOUND button.")

if __name__ == "__main__":
    main()
